class BankAccount {
  private balance = 0;

  deposit(amount: number): void {
    if (amount <= 0) throw new Error("amount must be positive");
    this.balance += amount;
  }

  getBalance(): number {
    return this.balance;
  }
}

class CartItem {
  constructor(public readonly sku: string, private quantity: number) {}

  increment(): void {
    this.quantity += 1;
  }

  getQuantity(): number {
    return this.quantity;
  }
}

class Temperature {
  private celsius = 0;

  setCelsius(value: number): void {
    if (Number.isNaN(value)) throw new Error("invalid temperature");
    this.celsius = value;
  }

  getFahrenheit(): number {
    return (this.celsius * 9) / 5 + 32;
  }
}

